adj=defaultdict(set)
for u,v in edges:
    adj[u].add(v); adj[v].add(u)

def ego(seed, k):
    seen={seed}; layer={seed}
    for _ in range(k):
        nxt=set()
        for n in layer:
            for m in adj[n]:
                if m not in seen:
                    seen.add(m); nxt.add(m)
        layer=nxt
    return seen
